import { useEffect, useRef, useState } from "react";
import { createPortal } from "react-dom";
import styles from "./layout.module.scss";
import { useTranslation } from "react-i18next";

export default function Footer() {
const { t } = useTranslation();

  const [footerRoot, setFooterRoot] = useState(null);
  const footerRef = useRef(null);

  useEffect(() => {
    const footerEl = document.getElementById("footer");
    if (footerEl) setFooterRoot(footerEl);
  }, []);

  useEffect(() => {
    if (!footerRoot || !footerRef.current) return;

    const observer = new IntersectionObserver(
      (entries, obs) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add(styles.view);
            obs.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.2 }
    );

    observer.observe(footerRef.current);

    return () => observer.disconnect();
  }, [footerRoot]);

  if (!footerRoot) return null;

  return createPortal(
    <div className={`${styles.footerInner} ${styles.animate}`} ref={footerRef}>
      <p>{t("footer.quote")}</p>
      <a href="mailto:lovesong001109@gmail.com">lovesong001109@gmail.com</a>
      <ul>
        <li><a href="tel:01054085146">010-5408-5146</a></li>
        <li>
          <a href="https://github.com/MinJ1109" target="_blank" rel="noopener noreferrer">
            https://github.com/MinJ1109
          </a>
        </li>
      </ul>
      <p>
        어제의 나에게 부끄럽지 않게 꾸준히 공부하고 성장하기 위해 노력합니다.<br />
        변화하는 웹 트렌드와 사용자 경험을 정확히 파악하며, 더 나은 결과물을 만들기 위해 움직이는 퍼블리셔가 되겠습니다.
      </p>
      <span>
        본 사이트는 상업적 목적이 아닌 개인의 포트폴리오용으로 제작되었습니다
        <span>© 2025 Minju Lee. All Rights Reserved.</span>
      </span>
    </div>,
    footerRoot
  );
}
